INSERT INTO `acga_scale` VALUES (1, '运动功能筛查', 'exercise', 2, NULL, '2026-05-26 11:44:21', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (2, '视力简易评估', 'vision', 4, '评判标准：4 分，视力正常；3 分，低视力；1～2 分，盲；0 分，完全失明。≤3 分应进一步到眼科评估。', '2026-05-26 11:45:47', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (3, '视觉功能简易评估', 'visual_function', 3, '注 1：评判方法：0 分=是，1 分=否；最终得分为以上 3 项得分的总和。 \r\n注 2：评判标准：3 分，视功能良好；2 分，视功能较差；≤1 分，视功能差；如第 1 项回答为“是”，说明视力有问题', '2026-05-26 14:46:13', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (4, '听力简易评估', 'listening', 4, '评判标准：4 分，听力正常；3 分，听力下降；1～2 分，听力障碍；0 分，完全失聪。≤3 分应进一步到耳鼻喉科评估。', '2026-05-26 14:54:22', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (5, '认知功能筛查', 'cognition', 5, '注 1：评判方法：画钟试验的数字标注正确且指针显示时间正确，判断为正确。 \r\n注 2：评判标准：每回忆 1 个词得 1 分；画钟试验正确为 2 分，错误为 0 分。将名词回忆和画钟试验的总分相加为简易智力评估得分。0～2 分，认知功能障碍筛查阳性；3～5 分，认知功能障碍筛查阴性。', '2026-05-26 14:59:18', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (6, '抑郁筛查', 'depression', 1, '过去两周内做事时是否提不起劲或没有兴趣，或是否感到心情低落、沮丧或绝望；阳性建议进行抑郁评估 WS/T802 B4。', '2026-05-26 15:09:24', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (7, '焦虑筛查', 'anxiety', 1, '过去两周内是否感觉紧张、担忧或急切，或是否不能够停止或控制担忧；阳性建议进行焦虑评估 WS/T802 B3。', '2026-05-26 15:12:25', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (8, '居家环境筛查', 'stay_at_home', 14, NULL, '2026-05-26 15:15:47', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (9, '跌倒筛查', 'fall', 1, '阳性建议进行跌倒风险评估 MZT 185 A1。', '2026-05-26 15:35:12', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (10, '衰弱评估', 'frailty', 5, '≥3 分 = 衰弱，1-2 分 = 衰弱前期，0 分 = 无衰弱', '2026-05-26 15:40:12', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (11, '尿失禁筛查', 'incontinence', 1, '阳性建议进行尿失禁评估 B11。', '2026-05-26 15:47:58', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (12, '便秘筛查', 'constipation', 1, '阳性建议进行便秘评估 B12。', '2026-05-26 15:49:56', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (13, '睡眠障碍筛查', 'sleep', 1, '阳性建议进行睡眠障碍评估 B13。', '2026-05-26 15:51:20', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (14, '慢性疼痛筛查', 'chronic', 1, '阳性建议进行慢性疼痛评估 B14。', '2026-05-26 15:55:25', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (15, '压力性损伤风险筛查', 'pressure', 1, '阳性建议进行压力性损伤风险评估 B16。', '2026-05-26 15:58:30', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (16, '多重用药状态', 'medication', 2, '<5 种：无；5～9 种：轻度；≥10 种：重度。\r\n· 医疗机构操作规范：WS/T 888—2026《医疗机构老年综合评估技术操作标准》\r\n· 国内指南：《中国老年多重用药管理指南（2025）》', '2026-05-26 15:59:56', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (17, '吞咽障碍筛查', 'swallow', 1, '吃东西或喝水时出现咳嗽或呛咳为阳性，建议进行吞咽障碍评估 B17。', '2026-05-26 16:03:13', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (18, '营养风险筛查', 'nutrition', 14, '总分≤11分为营养不良风险，建议进行营养不良评估及诊断 B18/B19。', '2026-05-26 16:05:09', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (19, '肌少症筛查', 'sarcopenia', 1, '男性＜34 cm，女性＜33 cm 为肌少症筛查阳性；阳性建议进行肌肉力量和躯体功能评估。', '2026-05-26 16:29:17', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (20, '谵妄评估', 'delirium', 8, '注 1：评估方法：条目 1 中 1 或 2 任意一个问题答案为“是”，条目 1 结果判断均为阳性；条目 2、3 的问题，回答为 \r\n“是”，相应条目结果判断为阳性；存在条目 4 中任何一种临床表现异常，条目 4 结果判断为阳性。 \r\n注 2：评判标准：条目 1 和条目 2 均为阳性，且满足条目 3 或条目 4，诊断为谵妄。', '2026-05-26 16:31:07', '0', '2026-05-29 10:30:33', '', '');
INSERT INTO `acga_scale` VALUES (21, '日常生活活动能力', 'daily_life', 100, 'Barthel ADL评定量表，满分100分，≤40重度依赖；41-60中度依赖；61-99轻度依赖；100分无依赖', '2026-06-01 09:36:21', '0', '2026-06-01 16:49:40', '', '');
INSERT INTO `acga_scale` VALUES (22, '简易体能状况量表', 'sppb', 12, '评估老年人身体功能状况，包含平衡测试、步速测试、5次起坐试验三项', '2026-06-01 15:01:11', '0', '2026-06-01 15:33:03', '', '');
