INSERT INTO `cga_record` VALUES (65, 25, 1, 26, 2, '听力简易评估：听力障碍（2/4分）；耳语试验：双耳异常（0/4分）；检出异常项目 3 项', '听力障碍较明显，建议尽快耳鼻喉科专科评估，排查老年性聋、中耳炎、听神经瘤等病因，必要时佩戴助听器。 耳语试验双耳阳性，提示双侧听力障碍，建议尽快耳鼻喉科专科评估。 检出项目：1. 听力简易评估：C（2分）；2. 耳语试验（左耳）：B（0分）；3. 耳语试验（右耳）：B（0分）', '{\"501\":{\"optionIds\":[503],\"score\":2},\"502\":{\"optionIds\":[507],\"score\":0},\"503\":{\"optionIds\":[509],\"score\":0}}', '2026-06-10 09:40:41', '2026-06-10 09:40:41', '', '', '0');
INSERT INTO `cga_record` VALUES (66, 25, 1, 27, 2, '居家环境筛查：跌倒风险高（2/14分）；检出跌倒风险 12 项', '居家环境跌倒风险较高，存在多处安全隐患。建议立即进行全面整改，必要时进行适老化改造，避免跌倒事故发生。 风险项：1. B. 地板状况良好；2. D. 地板上有固定的防滑垫；3. E. 灯的亮度能够看清东西；4. F. 在床上开关灯方便；5. G. 晚上外边的路灯、楼道的灯照明良好；6. H. 淋浴室和浴池旁有扶手；7. I. 浴池和浴室有固定的防滑垫；8. J. 厕所接近浴室；9. K. 室内的楼梯旁都有可用的扶手；10. L. 室外的楼梯旁都有可用的扶手；11. M. 楼梯的边缘清晰；12. N. 房屋周围的路况良好', '{\"601\":{\"optionIds\":[601,603],\"score\":2}}', '2026-06-10 10:16:23', '2026-06-10 10:16:23', '', '', '0');
