INSERT INTO `cga_record` VALUES (69, 25, 1, 29, 2, 'FRAIL衰弱评估：衰弱前期（2/5分）；检出衰弱征象 2 项', '处于衰弱前期，存在潜在衰弱风险。建议加强营养摄入，适当进行抗阻运动，避免久坐，定期监测身体状态。 异常项：1. 疲乏：过去4周内大部分时间或者所有时间感到疲乏：符合；2. 阻力增加/耐力减退：在不用任何辅助工具及他人帮助的情况下，中途不休息爬1层楼梯有困难：符合', '{\"801\":{\"optionIds\":[801],\"score\":1},\"802\":{\"optionIds\":[803],\"score\":1},\"803\":{\"optionIds\":[806],\"score\":0},\"804\":{\"optionIds\":[808],\"score\":0},\"805\":{\"optionIds\":[810],\"score\":0}}', '2026-06-10 14:59:26', '2026-06-10 14:59:26', '', '', '0');
INSERT INTO `cga_record` VALUES (70, 25, 1, 30, 16, '尿失禁评估：重度尿失禁；漏尿类型：在未到达厕所之前就有漏尿、在咳嗽和打喷嚏时漏尿、在睡着时漏尿、在活动和体育运动时漏尿、在小便结束和穿好衣服时漏尿、没有明显原因的漏尿、一直漏尿', '重度尿失禁，严重影响日常生活和社交活动。建议尽快到专科就诊，评估手术治疗的可行性。 建议完善专科检查明确诊断。', '{\"901\":{\"optionIds\":[904],\"score\":3},\"902\":{\"optionIds\":[910],\"score\":6},\"903\":{\"optionIds\":[911],\"score\":0},\"904\":{\"optionIds\":[923,925,928,927,926,929,924],\"score\":7}}', '2026-06-10 16:00:33', '2026-06-10 16:00:59', '', '', '0');
INSERT INTO `cga_record` VALUES (71, 25, 1, 1, 6, 'AIS总分：6分，可能有睡眠障碍。入睡时间（关灯后到睡着的时间）：没问题(0分)；夜间苏醒：没问题(0分)；比期望的时间早醒：没问题(0分)；总睡眠时间：没问题(0分)；总睡眠质量（无论睡多长）：满意(0分)；白天情绪：正常(0分)；白天身体功能（体力或精神：如记忆力、认知力或注意力等）：严重影响(3分)；白天思睡：严重思睡(3分)', '存在轻度睡眠问题，建议调整作息时间，改善睡眠环境，避免睡前饮用咖啡、浓茶等刺激性饮品，适当增加日间运动。', '{\"1101\":{\"optionIds\":[1101],\"score\":0},\"1102\":{\"optionIds\":[1105],\"score\":0},\"1103\":{\"optionIds\":[1109],\"score\":0},\"1104\":{\"optionIds\":[1113],\"score\":0},\"1105\":{\"optionIds\":[1117],\"score\":0},\"1106\":{\"optionIds\":[1121],\"score\":0},\"1107\":{\"optionIds\":[1128],\"score\":3},\"1108\":{\"optionIds\":[1132],\"score\":3}}', '2026-06-11 10:03:19', '2026-06-11 10:03:19', '', '', '0');
INSERT INTO `cga_record` VALUES (72, 25, 1, 1, 14, '疼痛强度：静息时感疼痛较重（6分）；疼痛相关存在3项异常', '疼痛强度：静息时感疼痛较重（6分）。疼痛情况：部分紧绷（如皱眉）；呛咳，大部分时间能耐受；呻吟>3次/min且每次持续时间>3s。建议进一步进行疼痛评估，必要时到疼痛科或相关专科就诊，进行针对性的疼痛管理与治疗。', '{\"1201\":{\"optionIds\":[1207],\"score\":6},\"1202\":{\"optionIds\":[1213],\"score\":2},\"1203\":{\"optionIds\":[1216],\"score\":1},\"1204\":{\"optionIds\":[1221],\"score\":2},\"1205\":{\"optionIds\":[1226],\"score\":3}}', '2026-06-11 10:25:41', '2026-06-11 10:25:41', '', '', '0');
INSERT INTO `cga_record` VALUES (73, 25, 1, 1, 18, '高度风险。存在高度压力性损伤风险，强烈建议立即进行专业皮肤评估，使用高级减压设备（交替式气垫床），增加翻身频率，加强营养和水分管理，必要时到专科就诊制定详细护理方案。', '存在高度压力性损伤风险，强烈建议立即进行专业皮肤评估，使用高级减压设备（交替式气垫床），增加翻身频率，加强营养和水分管理，必要时到专科就诊制定详细护理方案。', '{\"1301\":{\"optionIds\":[1303],\"score\":3},\"1302\":{\"optionIds\":[1307],\"score\":3},\"1303\":{\"optionIds\":[1311],\"score\":3},\"1304\":{\"optionIds\":[1316],\"score\":4},\"1305\":{\"optionIds\":[1320],\"score\":4},\"1306\":{\"optionIds\":[1321],\"score\":1}}', '2026-06-11 10:41:32', '2026-06-11 10:41:32', '', '', '0');
INSERT INTO `cga_record` VALUES (74, 22, 1, 1, 4, '轻度吞咽困难。存在轻度吞咽困难。', '存在轻度吞咽困难。建议调整饮食质地（软食、糊状食物），进食时采取坐位或半卧位，小口慢咽，每次吞咽后清嗓确认，必要时进行吞咽功能训练。', '{\"1401\":{\"optionIds\":[1404],\"score\":4}}', '2026-06-11 10:52:17', '2026-06-11 10:52:17', '', '', '0');
INSERT INTO `cga_record` VALUES (75, 22, 1, 36, 6, '总分：6分（基础分6分），营养不良', '存在明确的营养不良。强烈建议到营养科就诊，进行专业营养评估，制定个性化营养干预方案（包括饮食指导、口服营养补充或肠内营养支持），同时排查导致营养不良的基础疾病。', '{\"1501\":{\"optionIds\":[1504],\"score\":3},\"1502\":{\"optionIds\":[1508],\"score\":3}}', '2026-06-11 15:34:18', '2026-06-11 15:34:18', '', '', '0');
