INSERT INTO `cga_record` VALUES (93, 29, 1, 26, 3, '听力简易评估：听力障碍（1/4分）；耳语试验：单耳异常（2/4分）；检出异常项目 2 项', '听力障碍较明显，建议尽快耳鼻喉科专科评估，排查老年性聋、中耳炎、听神经瘤等病因，必要时佩戴助听器。 耳语试验单耳阳性，提示单侧听力障碍，建议进一步纯音测听检查。 检出项目：1. 听力简易评估：讲话者大声说话或说话很慢，才能部分听见（1分）；2. 耳语试验（右耳）：无法正确重复3个及以上词语（阳性）（0分）', '{\"501\":{\"optionIds\":[504],\"score\":1},\"502\":{\"optionIds\":[506],\"score\":2},\"503\":{\"optionIds\":[509],\"score\":0}}', '2026-06-15 15:13:16', '2026-06-15 15:13:16', '', '', '0');
INSERT INTO `cga_record` VALUES (94, 29, 1, 27, 5, '居家环境筛查：跌倒风险高（5/14分）；检出跌倒风险 9 项', '居家环境跌倒风险较高，存在多处安全隐患。建议立即进行全面整改，必要时进行适老化改造，避免跌倒事故发生。 风险项：1. A. 通道无杂乱物品；2. B. 地板状况良好；3. C. 地板防滑；4. E. 灯的亮度能够看清东西；5. F. 在床上开关灯方便；6. H. 淋浴室和浴池旁有扶手；7. I. 浴池和浴室有固定的防滑垫；8. M. 楼梯的边缘清晰；9. N. 房屋周围的路况良好', '{\"601\":{\"optionIds\":[604,607,610,612,611],\"score\":5}}', '2026-06-15 15:16:16', '2026-06-15 15:16:16', '', '', '0');
