INSERT INTO `cga_record` VALUES (96, 29, 1, 30, 10, '尿失禁评估：中度尿失禁；漏尿类型：在睡着时漏尿', '中度尿失禁，已对日常生活产生一定影响。建议在医生指导下进行盆底肌康复治疗，必要时使用药物干预。 建议完善专科检查明确诊断。', '{\"901\":{\"optionIds\":[902],\"score\":1},\"902\":{\"optionIds\":[909],\"score\":4},\"903\":{\"optionIds\":[915],\"score\":4},\"904\":{\"optionIds\":[925],\"score\":1}}', '2026-06-15 15:37:45', '2026-06-15 15:37:45', '', '', '0');
INSERT INTO `cga_record` VALUES (97, 29, 1, 31, 0, '便秘评估：存在便秘症状。时间情况：症状开始到现在持续时间：4个月；其中大约有多长时间是有症状的：1个月。症状表现：排便时肛门直肠堵塞感、需要手法辅助排便【异常】；粪便性状：水样便【异常】。', '症状开始到现在持续时间：4个月，其中大约有多长时间是有症状的：1个月，主要表现为：排便时肛门直肠堵塞感、需要手法辅助排便；粪便性状：水样便。建议增加膳食纤维（蔬菜、水果、粗粮）摄入，每日饮水1500-2000ml，规律排便，避免久坐。 建议必要时到消化内科专科就诊，完善相关检查明确诊断。', '{\"1001\":{\"optionIds\":[],\"value\":{\"type\":\"duration\",\"years\":0,\"months\":4,\"unknown\":false,\"text\":\"4个月\"},\"score\":0},\"1002\":{\"optionIds\":[],\"value\":{\"type\":\"duration\",\"years\":0,\"months\":1,\"unknown\":false,\"text\":\"1个月\"},\"score\":0},\"1003\":{\"optionIds\":[1005,1003],\"value\":null,\"score\":0},\"1004\":{\"optionIds\":[1013],\"value\":null,\"score\":0}}', '2026-06-15 16:34:59', '2026-06-15 16:34:59', '', '', '0');
INSERT INTO `cga_record` VALUES (98, 29, 1, 33, 16, '疼痛强度：静息时感间歇疼痛（开始影响生活质量）（4分）；疼痛相关存在4项异常', '疼痛强度：静息时感间歇疼痛（开始影响生活质量）（4分）。疼痛情况：完全紧绷（如眼睛紧闭）；完全弯曲且手指弯曲；对抗呼吸机；呻吟>3次/min且每次持续时间>3s。建议关注疼痛情况，适当调整生活方式，如症状持续或加重，建议到专科就诊。', '{\"1201\":{\"optionIds\":[1205],\"value\":null,\"score\":4},\"1202\":{\"optionIds\":[1214],\"value\":null,\"score\":3},\"1203\":{\"optionIds\":[1218],\"value\":null,\"score\":3},\"1204\":{\"optionIds\":[1222],\"value\":null,\"score\":3},\"1205\":{\"optionIds\":[1226],\"value\":null,\"score\":3}}', '2026-06-15 16:35:35', '2026-06-15 16:35:35', '', '', '0');
