INSERT INTO `cga_record` VALUES (100, 29, 1, 35, 4, '轻度吞咽困难。存在轻度吞咽困难。', '存在轻度吞咽困难。建议调整饮食质地（软食、糊状食物），进食时采取坐位或半卧位，小口慢咽，每次吞咽后清嗓确认，必要时进行吞咽功能训练。', '{\"1401\":{\"optionIds\":[1404],\"value\":null,\"score\":4}}', '2026-06-15 16:37:55', '2026-06-15 16:37:55', '', '', '0');
INSERT INTO `cga_record` VALUES (101, 29, 1, 41, 0, '本次跌倒风险评估共发现 6 项风险因素，存在高度跌倒风险。', '跌倒风险评估提示高度风险，建议立即进行多因素干预：综合评估与处理可逆危险因素、完善家居安全改造、使用合适的助行器具与防滑鞋履、加强护理与陪护，并结合临床进一步评估处理。', '{\"2001\":{\"optionIds\":[2002],\"value\":null,\"score\":0},\"2002\":{\"optionIds\":[2004],\"value\":null,\"score\":0},\"2003\":{\"optionIds\":[2006],\"value\":null,\"score\":0},\"2004\":{\"optionIds\":[2009],\"value\":null,\"score\":0},\"2005\":{\"optionIds\":[2011],\"value\":null,\"score\":0},\"2006\":{\"optionIds\":[2013],\"value\":null,\"score\":0}}', '2026-06-15 16:38:28', '2026-06-15 16:38:28', '', '', '0');
