INSERT INTO `cga_record` VALUES (112, 29, 1, 29, 3, 'FRAIL衰弱评估：衰弱（3/5分）；检出衰弱征象 3 项', '已检出衰弱状态，跌倒、失能风险显著升高。建议立即进行全面老年综合评估，制定个体化营养、运动和康复干预方案。 异常项：1. 自由活动下降：在不用任何辅助工具及他人帮助的情况下，走完1个街区（100m）较困难：符合；2. 疾病情况：医生告知存在5种及以上以下疾病（高血压、糖尿病、急性心脏病发作、卒中、恶性肿瘤、充血性心力衰竭、哮喘、关节炎、慢性肺病、肾脏疾病、心绞痛等）：符合；3. 体重下降：1年或更短时间内出现体重下降≥5%：符合', '{\"801\":{\"optionIds\":[802],\"value\":null,\"score\":0},\"802\":{\"optionIds\":[804],\"value\":null,\"score\":0},\"803\":{\"optionIds\":[805],\"value\":null,\"score\":1},\"804\":{\"optionIds\":[807],\"value\":null,\"score\":1},\"805\":{\"optionIds\":[809],\"value\":null,\"score\":1}}', '2026-06-16 15:08:09', '2026-06-16 15:08:09', '', '', '0');
