INSERT INTO `cga_record` VALUES (121, 31, 1, 25, 5, '视力评估：低视力；视觉功能评估：视觉功能较差；检出异常项目 2 项', '存在低视力，应考虑是否有屈光不正、早期白内障或干眼症等问题，建议眼科就诊完善视力及验光检查。 视觉功能较差，建议眼科就诊排查白内障、青光眼等病因。', '{\"401\":{\"optionIds\":[402],\"value\":null,\"score\":3},\"402\":{\"optionIds\":[407],\"value\":null,\"score\":1},\"403\":{\"optionIds\":[409],\"value\":null,\"score\":1},\"404\":{\"optionIds\":[410],\"value\":null,\"score\":0}}', '2026-06-16 16:57:12', '2026-06-16 16:57:12', '', '', '0');
INSERT INTO `cga_record` VALUES (122, 31, 1, 26, 5, '听力简易评估：听力下降；耳语试验：单耳异常；检出异常项目 2 项', '存在轻度听力下降，应考虑是否有耵聍栓塞、早期老年性聋或中耳炎等问题，建议耳鼻喉科就诊完善纯音测听检查。 耳语试验单耳阳性，提示单侧听力障碍，建议进一步纯音测听检查。', '{\"501\":{\"optionIds\":[502],\"value\":null,\"score\":3},\"502\":{\"optionIds\":[506],\"value\":null,\"score\":2},\"503\":{\"optionIds\":[509],\"value\":null,\"score\":0}}', '2026-06-16 16:57:24', '2026-06-16 16:57:24', '', '', '0');
INSERT INTO `cga_record` VALUES (123, 31, 1, 27, 6, '居家环境筛查：跌倒风险高（6/14分）；检出跌倒风险 8 项', '居家环境跌倒风险较高，存在多处安全隐患。建议立即进行全面整改，必要时进行适老化改造，避免跌倒事故发生。 风险项：1. 通道无杂乱物品；2. 地板状况良好；3. 地板防滑；4. 地板上有固定的防滑垫；5. 在床上开关灯方便；6. 淋浴室和浴池旁有扶手；7. 楼梯的边缘清晰；8. 房屋周围的路况良好', '{\"601\":{\"optionIds\":[607,609,610,605,611,612],\"value\":null,\"score\":6}}', '2026-06-16 16:57:35', '2026-06-16 16:57:35', '', '', '0');
INSERT INTO `cga_record` VALUES (124, 31, 1, 25, 5, '盲；视觉功能良好；检出异常项目 1 项', '视力已达盲标准，建议尽快眼科专科评估，排查白内障、青光眼、黄斑病变等严重眼部疾病。 视觉功能正常，无明显异常。', '{\"401\":{\"optionIds\":[403],\"value\":null,\"score\":2},\"402\":{\"optionIds\":[407],\"value\":null,\"score\":1},\"403\":{\"optionIds\":[409],\"value\":null,\"score\":1},\"404\":{\"optionIds\":[411],\"value\":null,\"score\":1}}', '2026-06-16 17:00:43', '2026-06-16 17:00:43', '', '', '0');
INSERT INTO `cga_record` VALUES (125, 31, 1, 25, 3, '盲；视觉功能差；检出异常项目 3 项', '视力已达盲标准，建议尽快眼科专科评估，排查白内障、青光眼、黄斑病变等严重眼部疾病。 视觉功能差，存在明显视物异常，建议尽快眼科专科评估，排查黄斑变性、视网膜病变等疾病。', '{\"401\":{\"optionIds\":[403],\"value\":null,\"score\":2},\"402\":{\"optionIds\":[406],\"value\":null,\"score\":0},\"403\":{\"optionIds\":[408],\"value\":null,\"score\":0},\"404\":{\"optionIds\":[411],\"value\":null,\"score\":1}}', '2026-06-16 17:01:15', '2026-06-16 17:01:15', '', '', '0');
INSERT INTO `cga_record` VALUES (126, 31, 1, 27, 5, '居家环境筛查：跌倒风险高（5/14分）；检出跌倒风险 9 项', '居家环境跌倒风险较高，存在多处安全隐患。建议立即进行全面整改，必要时进行适老化改造，避免跌倒事故发生。 风险项：1. 通道杂乱物品；2. 地板状况；3. 地板防滑；4. 灯光亮度；5. 夜间室外及楼道照明；6. 淋浴室和浴池扶手；7. 厕所与浴室距离；8. 楼梯边缘；9. 房屋周围的路况', '{\"601\":{\"optionIds\":[604,606,612,609,611],\"value\":null,\"score\":5}}', '2026-06-16 17:24:39', '2026-06-16 17:24:39', '', '', '0');
INSERT INTO `cga_record` VALUES (127, 31, 1, 27, 8, '居家环境筛查：跌倒风险中等（8/14分）；检出跌倒风险 6 项', '居家环境存在一定跌倒风险。建议针对检出的风险项进行整改，重点改善照明、地面防滑和扶手配置，消除潜在隐患。 风险项：1. 通道杂乱物品；2. 地板状况；3. 地板固定防滑垫；4. 浴池和浴室固定防滑垫；5. 厕所与浴室距离；6. 房屋周围的路况', '{\"601\":{\"optionIds\":[603,605,608,606,607,612,611,613],\"value\":null,\"score\":8}}', '2026-06-16 17:24:59', '2026-06-16 17:24:59', '', '', '0');
INSERT INTO `cga_record` VALUES (128, 31, 1, 30, 14, '尿失禁评估：中度尿失禁；漏尿类型：在睡着时漏尿、在活动和体育运动时漏尿', '中度尿失禁，已对日常生活产生一定影响。建议在医生指导下进行盆底肌康复治疗，必要时使用药物干预。 建议完善专科检查明确诊断。', '{\"901\":{\"optionIds\":[904],\"value\":null,\"score\":3},\"902\":{\"optionIds\":[908],\"value\":null,\"score\":2},\"903\":{\"optionIds\":[918],\"value\":null,\"score\":7},\"904\":{\"optionIds\":[925,926],\"value\":null,\"score\":2}}', '2026-06-16 17:25:15', '2026-06-16 17:25:15', '', '', '0');
INSERT INTO `cga_record` VALUES (129, 31, 1, 31, 0, '便秘评估：存在便秘症状。时间情况：症状开始到现在持续时间：1年7个月；其中大约有多长时间是有症状的：1年。症状表现：排便次数减少（每周<3次）、排便费时【异常】；粪便性状：腊肠样/蛇状，光滑柔软【异常】。', '症状开始到现在持续时间：1年7个月，其中大约有多长时间是有症状的：1年，主要表现为：排便次数减少（每周<3次）、排便费时；粪便性状：腊肠样/蛇状，光滑柔软。建议增加膳食纤维（蔬菜、水果、粗粮）摄入，每日饮水1500-2000ml，规律排便，避免久坐。 建议必要时到消化内科专科就诊，完善相关检查明确诊断。', '{\"1001\":{\"optionIds\":[],\"value\":{\"type\":\"duration\",\"years\":1,\"months\":7,\"unknown\":false,\"text\":\"1年7个月\"},\"score\":0},\"1002\":{\"optionIds\":[],\"value\":{\"type\":\"duration\",\"years\":1,\"months\":0,\"unknown\":false,\"text\":\"1年\"},\"score\":0},\"1003\":{\"optionIds\":[1001,1004],\"value\":null,\"score\":0},\"1004\":{\"optionIds\":[1010],\"value\":null,\"score\":0}}', '2026-06-16 17:25:28', '2026-06-16 17:25:28', '', '', '0');
INSERT INTO `cga_record` VALUES (130, 31, 1, 33, 16, '疼痛强度：静息时感疼痛较重（6分）；疼痛相关存在4项异常', '疼痛强度：静息时感疼痛较重。疼痛情况：部分紧绷（如皱眉）；部分弯曲；对抗呼吸机；呻吟>3次/min且每次持续时间>3s。建议进一步进行疼痛评估，必要时到疼痛科或相关专科就诊，进行针对性的疼痛管理与治疗。', '{\"1201\":{\"optionIds\":[1207],\"value\":null,\"score\":6},\"1202\":{\"optionIds\":[1213],\"value\":null,\"score\":2},\"1203\":{\"optionIds\":[1217],\"value\":null,\"score\":2},\"1204\":{\"optionIds\":[1222],\"value\":null,\"score\":3},\"1205\":{\"optionIds\":[1226],\"value\":null,\"score\":3}}', '2026-06-16 17:25:58', '2026-06-16 17:25:58', '', '', '0');
INSERT INTO `cga_record` VALUES (131, 31, 1, 34, 16, '高度风险。存在高度压力性损伤风险，强烈建议立即进行专业皮肤评估，使用高级减压设备（交替式气垫床），增加翻身频率，加强营养和水分管理，必要时到专科就诊制定详细护理方案。', '存在高度压力性损伤风险，强烈建议立即进行专业皮肤评估，使用高级减压设备（交替式气垫床），增加翻身频率，加强营养和水分管理，必要时到专科就诊制定详细护理方案。', '{\"1301\":{\"optionIds\":[1304],\"value\":null,\"score\":4},\"1302\":{\"optionIds\":[1307],\"value\":null,\"score\":3},\"1303\":{\"optionIds\":[1310],\"value\":null,\"score\":2},\"1304\":{\"optionIds\":[1315],\"value\":null,\"score\":3},\"1305\":{\"optionIds\":[1319],\"value\":null,\"score\":3},\"1306\":{\"optionIds\":[1321],\"value\":null,\"score\":1}}', '2026-06-16 17:26:09', '2026-06-16 17:26:09', '', '', '0');
INSERT INTO `cga_record` VALUES (132, 31, 1, 35, 3, '轻度吞咽困难。存在轻度吞咽困难。', '存在轻度吞咽困难。建议调整饮食质地（软食、糊状食物），进食时采取坐位或半卧位，小口慢咽，每次吞咽后清嗓确认，必要时进行吞咽功能训练。', '{\"1401\":{\"optionIds\":[1403],\"value\":null,\"score\":3}}', '2026-06-16 17:26:19', '2026-06-16 17:26:19', '', '', '0');
INSERT INTO `cga_record` VALUES (133, 31, 1, 36, 3, '总分：3分（基础分3分），存在营养不良风险', '存在营养不良风险。建议加强膳食指导：增加优质蛋白（鸡蛋、牛奶、鱼、豆制品）摄入，每天至少三餐并适当加餐，鼓励户外活动，必要时补充口服营养制剂（ONS）。', '{\"1501\":{\"optionIds\":[1503],\"value\":null,\"score\":2},\"1502\":{\"optionIds\":[1506],\"value\":null,\"score\":1}}', '2026-06-16 17:26:33', '2026-06-16 17:26:33', '', '', '0');
INSERT INTO `cga_record` VALUES (134, 31, 1, 36, 4, '总分：4分（基础分4分），营养不良', '存在明确的营养不良。强烈建议到营养科就诊，进行专业营养评估，制定个性化营养干预方案（包括饮食指导、口服营养补充或肠内营养支持），同时排查导致营养不良的基础疾病。', '{\"1501\":{\"optionIds\":[1502],\"value\":null,\"score\":1},\"1502\":{\"optionIds\":[1508],\"value\":null,\"score\":3}}', '2026-06-16 17:27:01', '2026-06-16 17:27:01', '', '', '0');
INSERT INTO `cga_record` VALUES (135, 31, 1, 41, 0, '本次跌倒风险评估共发现 2 项风险因素，存在中度跌倒风险。', '跌倒风险评估提示中度风险，建议加强预防措施：改善家居环境、必要时使用辅助行走器具、穿着防滑鞋、进行平衡与肌力训练、加强陪护与观察。', '{\"2001\":{\"optionIds\":[2001],\"value\":null,\"score\":0},\"2002\":{\"optionIds\":[2003],\"value\":null,\"score\":0},\"2003\":{\"optionIds\":[2006],\"value\":null,\"score\":0},\"2004\":{\"optionIds\":[2009],\"value\":null,\"score\":0},\"2005\":{\"optionIds\":[2010],\"value\":null,\"score\":0},\"2006\":{\"optionIds\":[2014],\"value\":null,\"score\":0}}', '2026-06-16 17:27:15', '2026-06-16 17:27:15', '', '', '0');
INSERT INTO `cga_record` VALUES (136, 31, 1, 42, 0, '本次多重用药评估共发现 4 项用药相关问题，存在中度多重用药风险。', '多重用药评估提示存在中度多重用药风险，建议尽快至临床药师或专科医生处进行用药重整，评估重复用药、药物相互作用及潜在不良反应，优化用药方案。', '{\"2101\":{\"optionIds\":[2101],\"value\":null,\"score\":0},\"2102\":{\"optionIds\":[2104],\"value\":null,\"score\":0},\"2103\":{\"optionIds\":[2105],\"value\":null,\"score\":0},\"2104\":{\"optionIds\":[2107],\"value\":null,\"score\":0},\"2105\":{\"optionIds\":[2109],\"value\":null,\"score\":0}}', '2026-06-16 17:27:34', '2026-06-16 17:27:34', '', '', '0');
INSERT INTO `cga_record` VALUES (137, 31, 1, 37, 10, '微营养筛选量表：5 分；营养标准量表：5 分；综合评分：10 分；评估结论：营养不良', '存在明确的营养不良。强烈建议：（1）尽快到营养科或老年科就诊，进行专业营养评估（如血清白蛋白、前白蛋白、血红蛋白等指标检测）；（2）制定个性化营养干预方案，包括饮食指导、口服营养补充或必要时肠内营养支持；（3）排查导致营养不良的基础疾病并进行针对性处理。', '{\"1601\":{\"optionIds\":[1602],\"value\":null,\"score\":1},\"1602\":{\"optionIds\":[1605],\"value\":null,\"score\":1},\"1603\":{\"optionIds\":[1608],\"value\":null,\"score\":0},\"1604\":{\"optionIds\":[1612],\"value\":null,\"score\":2},\"1605\":{\"optionIds\":[1614],\"value\":null,\"score\":1},\"1606\":{\"optionIds\":[],\"value\":[],\"score\":0},\"1607\":{\"optionIds\":[1620],\"value\":null,\"score\":0},\"1701\":{\"optionIds\":[1703],\"value\":null,\"score\":1},\"1702\":{\"optionIds\":[1706],\"value\":null,\"score\":1},\"1703\":{\"optionIds\":[1708],\"value\":null,\"score\":1},\"1704\":{\"optionIds\":[1710],\"value\":null,\"score\":1},\"1705\":{\"optionIds\":[1714],\"value\":null,\"score\":1},\"1706\":{\"optionIds\":[],\"value\":[],\"score\":0},\"1707\":{\"optionIds\":[1719],\"value\":null,\"score\":0}}', '2026-06-16 17:27:56', '2026-06-16 17:27:56', '', '', '0');
INSERT INTO `cga_record` VALUES (138, 31, 1, 32, 13, 'AIS总分：13分，存在睡眠障碍', '存在明确的睡眠障碍，建议进一步完善睡眠相关检查，评估睡眠障碍类型，并给予针对性的干预和治疗。', '{\"1101\":{\"optionIds\":[1103],\"value\":null,\"score\":2},\"1102\":{\"optionIds\":[1107],\"value\":null,\"score\":2},\"1103\":{\"optionIds\":[1110],\"value\":null,\"score\":1},\"1104\":{\"optionIds\":[1115],\"value\":null,\"score\":2},\"1105\":{\"optionIds\":[1119],\"value\":null,\"score\":2},\"1106\":{\"optionIds\":[1123],\"value\":null,\"score\":2},\"1107\":{\"optionIds\":[1127],\"value\":null,\"score\":2},\"1108\":{\"optionIds\":[1129],\"value\":null,\"score\":0}}', '2026-06-16 17:28:13', '2026-06-16 17:28:13', '', '', '0');
