INSERT INTO `cga_scale` VALUES (33, '老年人慢性疼痛综合评估量表', 'chronic_pain', 26, 'WS/T 888-2026 合并量表：包含慢性疼痛数字评定量表(NRS)和慢性疼痛行为评估量表(CPOT)；行为量表：插管患者评1+2+3题，非插管患者评1+2+4题', '2026-06-11 10:08:19', '2026-06-11 10:08:39', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (34, '老年人压力性损伤风险评估量表(Braden)', 'pressure_injury_ws_t888_2026', 23, 'WS/T 888-2026 压力性损伤风险评估量表；反向计分：分数越低风险越高；评判标准：≤9分极高危，10~12分高危，13~14分中危，15~18分低危', '2026-06-11 10:33:52', '2026-06-11 10:33:52', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (35, '洼田饮水试验（吞咽障碍评估）', 'swallowing', 5, 'WS/T 888-2026 老年人吞咽障碍评估；操作方法：患者坐位，饮用30ml温开水，观察饮水时间、呛咳及异常征象；评判结果：正常/可疑异常/异常', '2026-06-11 10:46:23', '2026-06-11 10:46:23', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (36, '老年人营养风险终筛表(NRS 2002)', 'nutrition', 7, 'WS/T 888-2026 营养风险终筛；总分0~7分；评判标准：0~2分每周复评，3~7分存在营养风险启动营养干预；年龄≥70岁加1分', '2026-06-11 15:19:30', '2026-06-11 16:04:13', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (37, '老年人微营养评定法(简表)(MNA-SF)', 'micro_nutrition', 14, 'WS/T 888-2026 微营养评定；总分0~14分；评判标准：≤11分存在营养不良风险；【核心规则】BMI与小腿围二选一评分，不要同时计分', '2026-06-11 16:02:41', '2026-06-11 16:04:20', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (38, '老年人营养不良诊断与分级标准(GLIM)', 'glim_malnutrition_ws_t888_2026', 0, 'WS/T 888-2026 全球领导人营养不良倡议标准；【诊断逻辑】任何1项表现型指标 + 任何1项病因型指标 = 确诊营养不良；【分级】符合严重程度任一为重度，否则为中度', '2026-06-11 16:20:28', '2026-06-11 16:20:28', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (39, '老年人谵妄（意识模糊）评估量表', 'delirium', 0, 'WS/T 888-2026 谵妄评估；【诊断逻辑】条目1是 AND 条目2是 AND (条目3是 OR 条目4是) = 诊断为谵妄；【条目1规则】任意一个子问题为是即选\"是\"', '2026-06-12 15:02:50', '2026-06-12 15:02:50', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (40, 'GDS-15简版老年抑郁量表', 'depression', 15, '【评分规则】正向题：选\"是\"得1分，选\"否\"得0分；反向题（1、5、7、11、13题）：选\"否\"得1分，选\"是\"得0分；【评判标准】≤4分：无抑郁；5~9分：可疑抑郁；≥10分：抑郁', '2026-06-12 15:55:17', '2026-06-12 15:55:17', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (41, '老年人跌倒风险筛查量表', 'fall_risk_screen', 0, '老年人跌倒风险初筛量表；评估跌倒相关危险因素，包括跌倒史、基础疾病、辅助用具、用药情况、步态及认知状态', '2026-06-12 16:24:04', '2026-06-12 16:24:04', 'admin', 'admin', '0');
INSERT INTO `cga_scale` VALUES (42, 'Beers不适当用药筛查量表', 'medication', 0, '老年人潜在不恰当用药(PIM)筛查；PIM：潜在不恰当用药；存在任意一项风险建议请药师会诊调整用药方案', '2026-06-12 16:49:50', '2026-06-12 16:55:21', 'admin', 'admin', '0');
